import React, { useState, useEffect } from "react";
import "./Dashboard.css";
import ExpenseForm from "./ExpenseForm";
import IncomeForm from "./IncomeForm";
import ExpenseList from "./ExpenseList";
import IncomeList from "./IncomeList";
import BalanceSummary from "./BalanceSummary";
import Stats from "./Stats";
import Profile from "./Profile";
import Settings from "./Settings";
import BudgetManager from "./BudgetManager";

const Dashboard = ({ onLogout }) => {
  const [activeTab, setActiveTab] = useState("overview");
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [user, setUser] = useState({ name: "Demo User", email: "demo@example.com" });

  useEffect(() => {
    const savedUser = localStorage.getItem('user');
    if (savedUser) setUser(JSON.parse(savedUser));
  }, []);

  const renderContent = () => {
    switch (activeTab) {
      case "overview":
        return (
          <div className="animate-fade-in">
            <BalanceSummary />
            <div className="dashboard-main-grid">
              <div className="section-card premium-card">
                <div className="section-header">
                  <h3>Recent Transactions</h3>
                </div>
                <div className="summaries-row">
                  <IncomeList />
                  <ExpenseList />
                </div>
              </div>
              <div className="section-card premium-card">
                <div className="section-header">
                  <h3>Add Transaction</h3>
                </div>
                <div className="forms-row">
                  <IncomeForm />
                  <ExpenseForm />
                </div>
              </div>
            </div>
          </div>
        );
      case "stats": return <Stats />;
      case "budget": return <BudgetManager />;
      case "profile": return <Profile />;
      case "settings": return <Settings />;
      default: return null;
    }
  };

  return (
    <div className="dashboard-container">
      <div className={`sidebar-overlay ${isSidebarOpen ? 'active' : ''}`} onClick={() => setIsSidebarOpen(false)}></div>
      
      <aside className={`sidebar ${isSidebarOpen ? 'open' : ''}`}>
        <h2 className="navbar-logo" style={{ marginBottom: '2rem' }}>Kiptaaz</h2>
        <nav className="sidebar-menu">
          <button 
            className={`sidebar-link ${activeTab === 'overview' ? 'active' : ''}`}
            onClick={() => { setActiveTab('overview'); setIsSidebarOpen(false); }}
          >
            <span>🏠</span> Overview
          </button>
          <button 
            className={`sidebar-link ${activeTab === 'stats' ? 'active' : ''}`}
            onClick={() => { setActiveTab('stats'); setIsSidebarOpen(false); }}
          >
            <span>📊</span> Statistics
          </button>
          <button 
            className={`sidebar-link ${activeTab === 'budget' ? 'active' : ''}`}
            onClick={() => { setActiveTab('budget'); setIsSidebarOpen(false); }}
          >
            <span>🎯</span> Budget
          </button>
          <button 
            className={`sidebar-link ${activeTab === 'profile' ? 'active' : ''}`}
            onClick={() => { setActiveTab('profile'); setIsSidebarOpen(false); }}
          >
            <span>👤</span> Profile
          </button>
          <button 
            className={`sidebar-link ${activeTab === 'settings' ? 'active' : ''}`}
            onClick={() => { setActiveTab('settings'); setIsSidebarOpen(false); }}
          >
            <span>⚙️</span> Settings
          </button>
        </nav>

        <button 
          className="premium-btn danger" 
          style={{ marginTop: 'auto', width: '100%' }}
          onClick={onLogout}
        >
          Logout
        </button>
      </aside>

      <header className="dashboard-header">
        <div className="user-welcome">
          <button className="premium-btn secondary" style={{ padding: '0.5rem', marginRight: '1rem' }} onClick={() => setIsSidebarOpen(true)}>
            ☰
          </button>
          <div>
            <h2>Hello, {user.name}</h2>
            <p>Here's what's happening with your money today.</p>
          </div>
        </div>
        <div className="header-actions">
          <button className="premium-btn" onClick={() => setActiveTab('overview')}>
            + New Transaction
          </button>
        </div>
      </header>

      <main className="dashboard-content">
        {renderContent()}
      </main>
    </div>
  );
};

export default Dashboard;
